var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"누구냐, 너희들은.","JPN":"君たちは何者だ。","ENG":"Who art thou?","TWN":"報上名來！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"특이한 복장이로군. 이방인인가.","JPN":"変わった服装だな。異邦人か。","ENG":"What curious liveries you don. Be you outsiders to this land?","TWN":"穿那什麼奇裝異服，是外邦人嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어, 그게……","JPN":"ええと、それが……","ENG":"Err, well…","TWN":"呃，那個……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"숲에서 길을 잃고 헤매다 여기까지 오게 됐지 뭐예요.","JPN":"森で道に迷って、ここまで辿り着いてしまったんです。","ENG":"We got lost in the woods and ended up wandering here.","TWN":"我們在森林裡迷路了，走著走著就走到這裡了。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"죄송하지만 여기가 어딘지 알려 주실 수 있을까요?","JPN":"すみませんが、ここがどこなのか教えていただけませんか？","ENG":"Would you mind telling us where we are?","TWN":"不好意思，請問你知道這裡是哪裡嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"흠. 길을 잃었는데도 여기까지 오다니, 행운의 여신께서 도우셨나 보군.","JPN":"ふむ。迷子になってここまで来るとは。幸運の女神様のお恵みだな。","ENG":"Hmph. Thou hast lost thine heading yet hast wandered hither? Why, Lady Fortune smileth upon thee.","TWN":"呵，迷路還可以走到這裡來，看來幸運女神很眷顧你們！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"여긴 센트럴 팰리스다.","JPN":"ここはセントラルパレスだ。","ENG":"This is the Central Palace.","TWN":"這裡是聖特羅貝里斯，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"아르카데나 제국의 수도이자, 인류의 마지막 보루지.","JPN":"アルカデナ帝国の首都であり、人類最後の砦である。","ENG":"The capital of the Empire of Arcadena, the final bastion of Man.","TWN":"就是艾爾卡特納帝國的首都，也是人類最後的堡壘。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"희한한 무기를 든 걸 보니 모험가인 모양이군. 맞나?","JPN":"珍しい武器を持っているということは、冒険者のようだな。違うか？","ENG":"Thy peculiar arms suggest thou earnest thy keep adventuring. Is that right?","TWN":"看你們手中拿著罕見的武器，你們是冒險家沒錯吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아, 하하. 맞아요, 모험가. 일거리를 찾으러 다니는 중이었어요.","JPN":"あ、はい、そうです。冒険者です、アハハ。仕事を探している途中だったんです。","ENG":"Oh... Haha... That's right. We're adventurers. Looking for a job.","TWN":"哦～哈哈，沒錯，我們正在找看看有沒有什麼事是可以做的。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"흠…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"도시 남쪽의 상업 지구에 모험가 조합이 있다. 일거리를 찾는다면 그리로 가 보도록.","JPN":"町の南の商業地区に冒険者ギルドがある。仕事を探すならそこに行ってみるといい。","ENG":"The Adventurer's Guild lies at the southern commercial district of the city. Head there if ye seek work.","TWN":"在南邊的商業區有個冒險家協會，你們可去那裡打聽看看！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"좋은 정보네요. 감사합니다.","JPN":"いい情報をありがとうございます。","ENG":"That's a great tip. Thank you.","TWN":"很棒的情報，謝謝你！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"아, 그리고 한 가지 더.","JPN":"ああ、あともう一つ。","ENG":"Ah, one more thing.","TWN":"喔，還有一件事！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"최근 센트럴 팰리스는 마왕의 수하들에게 쫓겨 온 난민들로 매우 소란스럽다.","JPN":"近頃セントラルパレスは、魔王の部下に追いやられた難民たちで非常に騒々しい。","ENG":"Central Palace has fallen into tumult lately from the deluge of refugees fleeing the Demon Lord's minions.","TWN":"最近聖特羅貝里斯因為那些被魔王趕出來的難民治安非常糟糕。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그러니 괜히 문제를 일으키지 말고 얌전히 지내라.","JPN":"なので、余計な揉め事を起こさないよう静かに過ごしてくれ。","ENG":"So do not go about causing trouble here.","TWN":"我勸你們最好安分一點，不要惹事。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"모험가랍시고 치안을 어지럽혔다간 추방되거나 감옥에 갇히게 될 테니까.","JPN":"冒険者とはいえ治安を乱したら、追放か監獄に閉じ込められることになるぞ。","ENG":"Else, you shall find yourselves exiled... or worse, in fetters.","TWN":"滋事的話，輕則被流放，重則是要進監牢的！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"마왕…… 이라고요?","JPN":"魔王……ですか？","ENG":"Did you say… Demon Lord?","TWN":"魔王是……？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"센트럴 팰리스? 아르카데나 제국? 게다가 마왕까지?","JPN":"セントラルパレス？　アルカデナ帝国？　それに魔王ですって？","ENG":"Central Palace? Empire of Arcadena? Demon Lord?","TWN":"聖特羅貝里斯？艾爾卡特納帝國？還有什麼魔王？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우효! 테마 파크치고는 설정도 제법 충실하잖아?","JPN":"ウヒョー！　テーマパークにしては設定もしっかりしてるじゃない？","ENG":"Wow! You guys really got the narrative down for this theme park!","TWN":"啊哈！這個主題樂園很不錯喔！工作人員都演得很認真欸！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L35_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"야, 야! 넌 눈치도 없어?! 딱 봐도 테마파크랑 거리가 멀잖아!","JPN":"ちょっと、空気読んでよ！　どう考えてもテーマパークじゃないでしょ！","ENG":"Oh come on! Are you really that clueless? This place is obviously no theme park!","TWN":"喂喂！你少白目！看也知道不是什麼主題樂園！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"위험할지도 모르니까 가만히 좀 있어!","JPN":"危ないかもしれないんだから、ちょっと黙ってて！","ENG":"Shut up before you get us into trouble!","TWN":"拜託你安靜點，不要給我們惹麻煩！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아앙? 내가 왜?","JPN":"はあ？　なんで私が？","ENG":"Huh? Why should I?","TWN":"什麼嘛？我哪有！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"설마 기사 흉내나 내는 아르바이트생들이 나한테 따지기라도 할 거란 말이야?","JPN":"あの騎士の真似したバイトスタッフが私相手に文句を言うと思ってるの？","ENG":"You think these part-time cosplayers pretending to be knights will challenge me to a duel or something?","TWN":"這些扮演騎士的工讀生難不成會找我麻煩嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"기사 흉내라고……?","JPN":"騎士の真似だと……？","ENG":"Pretending, say you?!","TWN":"扮演騎士的工讀生……？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L43_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"네놈들! 감히 대장님을 앞에 두고 무슨 무례냐!","JPN":"貴様ら！　隊長を前になんと無礼な！","ENG":"Thou wretch! How dare you insult us in front of our captain!","TWN":"大膽刁民！竟敢對隊長無禮！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"갑자기 나타난 것도 그렇고 아무리 봐도 수상한 놈들입니다.","JPN":"突然現れたのもそうですし、やはり怪しいやつらです。","ENG":"There's something suspicious about them, appearing out of thin air like this.","TWN":"突然出現就已經很可疑，現在再仔細一看，果然是一群可疑的傢伙！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"모험가가 아니라 마왕의 끄나풀일지도 모르잖습니까? 당장 체포해야 합니다!","JPN":"冒険者ではなく、魔王の手下かもしれません。今すぐ捕まえましょう！","ENG":"What if they're the Demon Lord's minions rather than adventurers? We should arrest them at once!","TWN":"我看你們根本不是冒險家，而是魔王的走狗吧！我要逮捕你們！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오해하지 마세요. 저희들은…….","JPN":"誤解しないでください、私たちは……","ENG":"I think there's been a misunderstanding. We are…","TWN":"請別誤會，我們是……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"……확실히 수상하군.","JPN":"……確かに怪しいな。","ENG":"…This is most suspicious indeed.","TWN":"……果然很可疑！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"제국에서 기사를 욕보이는 것이 얼마나 큰 결례인지 모르다니.","JPN":"帝国で騎士を侮辱する言動が、どれほど無礼なのかわからないとは。","ENG":"They know not the gravity of insulting an imperial knight.","TWN":"竟然不知道在帝國裡侮辱騎士可是重罪！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"……이방인도 포용하라는 성녀님의 말씀이 있어 가급적 정중히 대하려 했다.","JPN":"……異邦人も歓迎しろという聖女様のお言葉が\\nあったからこそ、できる限り丁重にもてなそうとしたが。","ENG":"I've tried my best to treat you with courtesy, given the Saintess's teachings about embracing outsiders.","TWN":"……要不是聖女說要包容外邦人，我才盡量對你們待之以理。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"나는 수도 방위 기사단, 3번대 대장 재클린이다.","JPN":"私は首都防衛騎士団、3番隊隊長、ジャクリーンだ。","ENG":"I am Jacques, the third captain of the Capital Defense Knights.","TWN":"我是首都護衛騎士團第3團隊長　杰克林！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"너희들은 누구냐? 어디서 온 자들이지?","JPN":"君たちは何者だ？　どこから来た？","ENG":"Who are you lot? Whence do you come?","TWN":"你們究竟是誰？從哪裡來的？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흐응? 결투 퍼포먼스인가?","JPN":"へえ、決闘パフォーマンス？","ENG":"Hmm... Are they reenacting a medieval duel?","TWN":"哦？現在是要表演打鬥戲嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이런 건 어울려 주는 게 방문객으로서의 예의겠지!","JPN":"こういうのはノってあげるのがゲストとしての礼儀じゃない？","ENG":"I wouldn't want to be rude and not play along!","TWN":"身為一位專業遊客當然要配合演出囉！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘?! 야, 이 바보야! 기다려!","JPN":"ナイエル！？　ちょっと待って！　このバカ！","ENG":"Naielle?! You idiot! Wait!","TWN":"奈爾？！你這個笨蛋！安靜啦！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"거기 너! 잘 듣도록!","JPN":"そこのあんた！　聞きなさい！","ENG":"You there! Listen up!","TWN":"喂，那個誰！你給我聽好！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"나는 단독으로 2종 침식체를 처치한 아카데미 최강의 쓰레기!","JPN":"私は一人で第2種侵食体を倒したアカデミー最強のゴミ！","ENG":"I am the best garbage in the Academy who single-handedly slayed a Category 2 C.O.!","TWN":"我是獨自處理掉2類侵蝕體的學院最強垃圾！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"나이엘 블루스틸 님이시다!","JPN":"ナイエル・ブルースチール様よ！","ENG":"I am Naielle Bluesteel!","TWN":"奈爾‧布魯斯提爾！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우리가 수상하다면 어디 실력으로 확인해 보시지!","JPN":"私たちが怪しいっていうなら、実力を確かめてみなさい！","ENG":"If you think we're suspicious, why don't you find out through combat?!","TWN":"你說我們很可疑？有本事就親自來確認啊！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어째 예전보다 상태가 더 나빠진 것 같은데…….","JPN":"なんだか前よりも状況が悪化してるような……","ENG":"Things just got a lot worse somehow...","TWN":"他怎麼好像比以前還嚴重……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"뭐, 이미 엎질러진 물이잖아.","JPN":"覆水盆に返らず、か。","ENG":"Oh well, no use crying over spilled milk.","TWN":"既然如此，只好…"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"준비해. 잔뜩 벼르고 있는 상대들한테 순순히 잡혀 줄 수는 없지.","JPN":"構えて。ご立腹の相手に簡単に捕まってあげるわけにはいかない。","ENG":"Get ready. We can't let them capture us.","TWN":"大家準備作戰！我們總不能乖乖挨打吧！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미카…….","JPN":"ミカさん……","ENG":"Mika…","TWN":"米卡……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"죄, 죄송해요! 학생회장님! 최면 마술은 앞으로 봉인할게요!","JPN":"す、すみません生徒会長！　催眠術はしばらく封印します！","ENG":"I-I'm so sorry! Student President! I'll disable the hypnosis spell from now on!","TWN":"會長抱歉！我以後會把催眠魔術封印起來！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……네. 꼭 부탁해요.","JPN":"……はい、ぜひお願いします。","ENG":"Yes… Please do.","TWN":"……好，拜託了。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"2종 침식체? 설마 2급 마족 얘긴가?","JPN":"第2種侵食体？　もしかして2級魔族の話か？","ENG":"Category 2 C.O.? Could she be talking about the demons of the second category?","TWN":"2類侵蝕體？你指的是2級魔族嗎？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"2급 마족을 혼자서 처치할 정도라면, 대장님도…….","JPN":"2級魔族を一人で倒せる実力者なら、隊長も……","ENG":"If she's capable of such a feat, perhaps our captain may not…","TWN":"可以獨自處理掉2級魔族的話，那隊長可能……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"흠. 당당하게 결투에 나서는 태도만은 칭찬 받을 만하군.","JPN":"ふむ。堂々と決闘に挑む姿勢だけは評価できるな。","ENG":"Hmm. I must applaud thy valorous attitude for battle.","TWN":"呵，光是敢正面迎戰的態度就值得嘉許！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"좋다. 어디 검술도 혓바닥 놀리는 재주만큼 뛰어난지 확인해 주지.","JPN":"いいだろう。貴様の剣術がその口の利き方のように上等なのか、確かめてやろう。","ENG":"Very well. We shall see if thy sword is as deft as thy tongue.","TWN":"很好！我就來看看你的刀法是否跟你的嘴巴一樣厲害！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"방위 기사단! 저 자들을 체포하라!","JPN":"防衛騎士団！　彼らを捕らえよ！","ENG":"Knights of the Capital Defense Order! Apprehend them!","TWN":"護衛騎士團！把人給我抓起來！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};